import scala.collection.mutable.PriorityQueue

def solve(value: Array[Long], limit: Array[Long]): Long = {
    val n = value.length
    val elements = value.zip(limit).sortBy(_._2)

    val heap = PriorityQueue.empty[Long](Ordering.by(-_))
    var activeCount = 0
    var total = 0L

    for ((v, l) <- elements) {
        if (activeCount < l) {
            heap.enqueue(v)
            total += v
            activeCount += 1
        } else {
            if (heap.nonEmpty && v > heap.head) {
                val smallest = heap.dequeue()
                total += v - smallest
                heap.enqueue(v)
            }
        }
    }

    total
}
